package undomanager.tests.incorrect;

import javax.swing.undo.UndoManager;

// Incorrect Test 0
// Violation: Calling void setLimit([int l]) in state Ended
public class TestIncorrect000 {
    public static void main(String[] args) {
        UndoManager undomanager = new UndoManager();
